BEGIN TRANSACTION;
CREATE TABLE "adjuntos_clinicos" ("id_adjunto" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre_archivo" varchar(150) NOT NULL, "ruta_archivo" varchar(255) NOT NULL, "tipo_mime" varchar(80) NOT NULL, "tamano_kb" integer unsigned NULL CHECK ("tamano_kb" >= 0), "fecha_subida" datetime NOT NULL, "id_usuario_sube" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "id_evolucion" integer NOT NULL REFERENCES "evoluciones_clinicas" ("id_evolucion") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "bitacora" ("id_bitacora" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "modulo" varchar(50) NOT NULL, "accion" varchar(50) NOT NULL, "tabla_afectada" varchar(50) NOT NULL, "id_registro_afectado" varchar(50) NOT NULL, "descripcion" varchar(255) NULL, "fecha_evento" datetime NOT NULL, "ip_origen" varchar(45) NULL, "id_usuario" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "box" ("id_box" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(50) NOT NULL UNIQUE, "ubicacion" varchar(100) NULL, "descripcion" varchar(150) NULL, "estado_box" varchar(20) NOT NULL);
CREATE TABLE "cajas" ("id_caja" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_apertura" datetime NOT NULL, "fecha_cierre" datetime NULL, "monto_inicial" decimal NOT NULL, "monto_final" decimal NULL, "estado_caja" varchar(20) NOT NULL, "id_usuario_apertura" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "id_usuario_cierre" integer NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "caras_dentales" ("id_cara_dental" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(30) NOT NULL UNIQUE);
CREATE TABLE "catalogo_antecedentes" ("id_catalogo_antecedente" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "tipo_antecedente" varchar(30) NOT NULL, "nombre" varchar(120) NOT NULL, "descripcion" varchar(200) NULL, "estado_antecedente" varchar(20) NOT NULL);
CREATE TABLE "citas" ("id_cita" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_hora_inicio" datetime NOT NULL, "fecha_hora_fin" datetime NOT NULL, "motivo_consulta" varchar(200) NULL, "observaciones" text NULL, "fecha_creacion" datetime NOT NULL, "fecha_actualizacion" datetime NOT NULL, "id_box" integer NOT NULL REFERENCES "box" ("id_box") DEFERRABLE INITIALLY DEFERRED, "id_odontologo" integer NOT NULL REFERENCES "odontologos" ("id_odontologo") DEFERRABLE INITIALLY DEFERRED, "id_paciente" integer NOT NULL REFERENCES "pacientes" ("id_paciente") DEFERRABLE INITIALLY DEFERRED, "id_usuario_registra" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "id_estado_cita" integer NOT NULL REFERENCES "estados_cita" ("id_estado_cita") DEFERRABLE INITIALLY DEFERRED, "id_tipo_atencion" integer NOT NULL REFERENCES "tipos_atencion" ("id_tipo_atencion") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "condiciones_odontologicas" ("id_condicion" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(50) NOT NULL UNIQUE, "descripcion" varchar(150) NULL, "estado_condicion" varchar(20) NOT NULL);
CREATE TABLE "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE "especialidades" ("id_especialidad" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(80) NOT NULL UNIQUE, "descripcion" varchar(150) NULL, "estado_especialidad" varchar(20) NOT NULL);
CREATE TABLE "estados_cita" ("id_estado_cita" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(30) NOT NULL UNIQUE, "descripcion" varchar(100) NULL);
CREATE TABLE "evoluciones_clinicas" ("id_evolucion" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_evolucion" datetime NOT NULL, "anamnesis" text NULL, "diagnostico" text NULL, "indicaciones" text NULL, "observaciones" text NULL, "id_cita" integer NOT NULL UNIQUE REFERENCES "citas" ("id_cita") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "fichas_clinicas" ("id_ficha_clinica" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "numero_ficha" varchar(30) NOT NULL UNIQUE, "fecha_apertura" date NOT NULL, "estado_ficha" varchar(20) NOT NULL, "observaciones_clinicas_generales" text NULL, "id_paciente" integer NOT NULL UNIQUE REFERENCES "pacientes" ("id_paciente") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "historial_citas" ("id_historial_cita" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "motivo_cambio" varchar(200) NULL, "fecha_cambio" datetime NOT NULL, "id_cita" integer NOT NULL REFERENCES "citas" ("id_cita") DEFERRABLE INITIALLY DEFERRED, "id_estado_anterior" integer NULL REFERENCES "estados_cita" ("id_estado_cita") DEFERRABLE INITIALLY DEFERRED, "id_estado_nuevo" integer NOT NULL REFERENCES "estados_cita" ("id_estado_cita") DEFERRABLE INITIALLY DEFERRED, "id_usuario_responsable" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "horarios_odontologo" ("id_horario" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "dia_semana" smallint unsigned NOT NULL CHECK ("dia_semana" >= 0), "hora_inicio" time NOT NULL, "hora_fin" time NOT NULL, "estado_horario" varchar(20) NOT NULL, "id_odontologo" integer NOT NULL REFERENCES "odontologos" ("id_odontologo") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "imagenologia_accesos_auditoria" ("id_acceso" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "accion" varchar(20) NOT NULL, "fecha_acceso" datetime NOT NULL, "ip_usuario" char(39) NULL, "usuario_id" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "archivo_id" integer NOT NULL REFERENCES "imagenologia_archivos" ("id_archivo") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "imagenologia_archivos" ("id_archivo" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "archivo" varchar(500) NOT NULL, "nombre_original" varchar(255) NOT NULL, "extension" varchar(20) NOT NULL, "tipo_mime" varchar(100) NOT NULL, "peso_bytes" bigint NOT NULL, "es_principal" bool NOT NULL, "estado" varchar(20) NOT NULL, "fecha_subida" datetime NOT NULL, "subido_por_id" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "examen_id" integer NOT NULL REFERENCES "imagenologia_examenes" ("id_examen") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "imagenologia_examenes" ("id_examen" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_examen" date NOT NULL, "centro_radiologico" varchar(150) NULL, "titulo" varchar(200) NULL, "descripcion" text NULL, "observacion_clinica" text NULL, "estado" varchar(20) NOT NULL, "fecha_creacion" datetime NOT NULL, "fecha_modificacion" datetime NOT NULL, "study_instance_uid" varchar(255) NULL, "orthanc_study_id" varchar(255) NULL, "cita_id" integer NULL REFERENCES "citas" ("id_cita") DEFERRABLE INITIALLY DEFERRED, "creado_por_id" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "evolucion_id" integer NULL REFERENCES "evoluciones_clinicas" ("id_evolucion") DEFERRABLE INITIALLY DEFERRED, "ficha_clinica_id" integer NULL REFERENCES "fichas_clinicas" ("id_ficha_clinica") DEFERRABLE INITIALLY DEFERRED, "paciente_id" integer NOT NULL REFERENCES "pacientes" ("id_paciente") DEFERRABLE INITIALLY DEFERRED, "solicitado_por_id" integer NULL REFERENCES "odontologos" ("id_odontologo") DEFERRABLE INITIALLY DEFERRED, "tipo_examen_id" integer NOT NULL REFERENCES "imagenologia_tipos_examen" ("id_tipo_examen") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "imagenologia_observaciones" ("id_observacion" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "observacion" text NOT NULL, "fecha_observacion" datetime NOT NULL, "examen_id" integer NOT NULL REFERENCES "imagenologia_examenes" ("id_examen") DEFERRABLE INITIALLY DEFERRED, "usuario_id" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "imagenologia_tipos_examen" ("id_tipo_examen" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(100) NOT NULL UNIQUE, "descripcion" varchar(255) NULL, "estado" varchar(20) NOT NULL, "fecha_creacion" datetime NOT NULL, "fecha_modificacion" datetime NOT NULL);
CREATE TABLE "medios_pago" ("id_medio_pago" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(50) NOT NULL UNIQUE, "descripcion" varchar(100) NULL, "estado_medio_pago" varchar(20) NOT NULL);
CREATE TABLE "movimientos_caja" ("id_movimiento_caja" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "descripcion" varchar(150) NULL, "monto" decimal NOT NULL, "fecha_movimiento" datetime NOT NULL, "id_caja" integer NOT NULL REFERENCES "cajas" ("id_caja") DEFERRABLE INITIALLY DEFERRED, "id_pago" integer NULL UNIQUE REFERENCES "pagos" ("id_pago") DEFERRABLE INITIALLY DEFERRED, "id_usuario_registra" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "id_tipo_movimiento" integer NOT NULL REFERENCES "tipos_movimiento_caja" ("id_tipo_movimiento") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "odontograma_detalle" ("id_odontograma_detalle" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "observacion" varchar(150) NULL, "id_cara_dental" integer NOT NULL REFERENCES "caras_dentales" ("id_cara_dental") DEFERRABLE INITIALLY DEFERRED, "id_condicion" integer NOT NULL REFERENCES "condiciones_odontologicas" ("id_condicion") DEFERRABLE INITIALLY DEFERRED, "id_odontograma" integer NOT NULL REFERENCES "odontogramas" ("id_odontograma") DEFERRABLE INITIALLY DEFERRED, "codigo_pieza_dental" varchar(10) NOT NULL REFERENCES "piezas_dentales" ("codigo_pieza_dental") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "odontograma_historial" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "tipo_cambio" varchar(50) NOT NULL, "detalle_cambio" text NOT NULL, "fecha" datetime NOT NULL, "odontograma_id" integer NOT NULL REFERENCES "odontogramas" ("id_odontograma") DEFERRABLE INITIALLY DEFERRED, "pieza_dental_id" varchar(10) NOT NULL REFERENCES "piezas_dentales" ("codigo_pieza_dental") DEFERRABLE INITIALLY DEFERRED, "usuario_id" integer NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "odontograma_periodontal" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "movilidad" varchar(20) NULL, "profundidad_sondaje" varchar(50) NULL, "recesion" varchar(50) NULL, "sangrado" bool NOT NULL, "placa" bool NOT NULL, "supuracion" bool NOT NULL, "furca" varchar(20) NULL, "observacion" text NULL, "pieza_id" integer NOT NULL UNIQUE REFERENCES "odontograma_pieza" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "odontograma_pieza" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "estado_general" varchar(30) NOT NULL, "observacion" text NULL, "fecha_actualizacion" datetime NOT NULL, "codigo_pieza_dental_id" varchar(10) NOT NULL REFERENCES "piezas_dentales" ("codigo_pieza_dental") DEFERRABLE INITIALLY DEFERRED, "odontograma_id" integer NOT NULL REFERENCES "odontogramas" ("id_odontograma") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "odontograma_raiz" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "raiz" varchar(20) NOT NULL, "tercio" varchar(20) NOT NULL, "observacion" varchar(150) NULL, "id_condicion_id" integer NULL REFERENCES "condiciones_odontologicas" ("id_condicion") DEFERRABLE INITIALLY DEFERRED, "pieza_id" integer NOT NULL REFERENCES "odontograma_pieza" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "odontogramas" ("id_odontograma" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "version" smallint unsigned NOT NULL CHECK ("version" >= 0), "fecha_registro" datetime NOT NULL, "descripcion_general" text NULL, "estado_odontograma" varchar(20) NOT NULL, "id_ficha_clinica" integer NOT NULL REFERENCES "fichas_clinicas" ("id_ficha_clinica") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "odontologo_especialidad" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "es_principal" bool NOT NULL, "id_especialidad" integer NOT NULL REFERENCES "especialidades" ("id_especialidad") DEFERRABLE INITIALLY DEFERRED, "id_odontologo" integer NOT NULL REFERENCES "odontologos" ("id_odontologo") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "odontologos" ("id_odontologo" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "numero_registro" varchar(30) NOT NULL UNIQUE, "duracion_cita_base_min" smallint unsigned NOT NULL CHECK ("duracion_cita_base_min" >= 0), "estado_profesional" varchar(20) NOT NULL, "id_usuario" integer NOT NULL UNIQUE REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "pacientes" ("id_paciente" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "contacto_emergencia_nombre" varchar(120) NULL, "contacto_emergencia_telefono" varchar(20) NULL, "observaciones_administrativas" text NULL, "fecha_registro" datetime NOT NULL, "id_persona" integer NOT NULL UNIQUE REFERENCES "personas" ("id_persona") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "pagos" ("id_pago" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_pago" datetime NOT NULL, "monto" decimal NOT NULL, "numero_comprobante" varchar(50) NULL UNIQUE, "estado_pago" varchar(20) NOT NULL, "id_medio_pago" integer NOT NULL REFERENCES "medios_pago" ("id_medio_pago") DEFERRABLE INITIALLY DEFERRED, "id_presupuesto" integer NOT NULL REFERENCES "presupuestos" ("id_presupuesto") DEFERRABLE INITIALLY DEFERRED, "id_usuario_registra" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "personas" ("id_persona" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "rut" varchar(12) NOT NULL UNIQUE, "nombres" varchar(80) NOT NULL, "apellido_paterno" varchar(50) NOT NULL, "apellido_materno" varchar(50) NULL, "fecha_nacimiento" date NULL, "correo" varchar(120) NULL UNIQUE, "telefono" varchar(20) NULL, "direccion" varchar(150) NULL, "comuna" varchar(80) NULL, "ciudad" varchar(80) NULL, "estado_persona" varchar(20) NOT NULL, "fecha_creacion" datetime NOT NULL, "fecha_actualizacion" datetime NOT NULL, "id_sexo" integer NULL REFERENCES "sexos" ("id_sexo") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "piezas_dentales" ("codigo_pieza_dental" varchar(10) NOT NULL PRIMARY KEY, "descripcion" varchar(100) NOT NULL, "estado_pieza" varchar(20) NOT NULL);
CREATE TABLE "plan_tratamiento_detalle" ("id_plan_detalle" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "cantidad" integer unsigned NOT NULL CHECK ("cantidad" >= 0), "valor_unitario" decimal NOT NULL, "estado_detalle" varchar(20) NOT NULL, "nivel_prioridad" smallint unsigned NULL CHECK ("nivel_prioridad" >= 0), "observaciones" varchar(200) NULL, "codigo_pieza_dental" varchar(10) NULL REFERENCES "piezas_dentales" ("codigo_pieza_dental") DEFERRABLE INITIALLY DEFERRED, "id_plan_tratamiento" integer NOT NULL REFERENCES "planes_tratamiento" ("id_plan_tratamiento") DEFERRABLE INITIALLY DEFERRED, "id_tratamiento" integer NOT NULL REFERENCES "tratamientos" ("id_tratamiento") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "planes_tratamiento" ("id_plan_tratamiento" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_creacion" datetime NOT NULL, "estado_plan" varchar(20) NOT NULL, "observaciones" text NULL, "id_ficha_clinica" integer NOT NULL REFERENCES "fichas_clinicas" ("id_ficha_clinica") DEFERRABLE INITIALLY DEFERRED, "id_odontologo" integer NOT NULL REFERENCES "odontologos" ("id_odontologo") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "presupuesto_detalle" ("id_presupuesto_detalle" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "descripcion_item" varchar(200) NOT NULL, "cantidad" integer unsigned NOT NULL CHECK ("cantidad" >= 0), "precio_unitario" decimal NOT NULL, "subtotal" decimal NOT NULL, "id_plan_detalle" integer NOT NULL REFERENCES "plan_tratamiento_detalle" ("id_plan_detalle") DEFERRABLE INITIALLY DEFERRED, "id_presupuesto" integer NOT NULL REFERENCES "presupuestos" ("id_presupuesto") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "presupuestos" ("id_presupuesto" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "numero_presupuesto" varchar(30) NOT NULL UNIQUE, "fecha_emision" datetime NOT NULL, "fecha_vencimiento" date NULL, "monto_bruto" decimal NOT NULL, "descuento_total" decimal NOT NULL, "monto_final" decimal NOT NULL, "estado_presupuesto" varchar(20) NOT NULL, "id_plan_tratamiento" integer NOT NULL REFERENCES "planes_tratamiento" ("id_plan_tratamiento") DEFERRABLE INITIALLY DEFERRED, "id_usuario_emite" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "registro_antecedente_detalle" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "detalle_adicional" varchar(200) NULL, "id_catalogo_antecedente" integer NOT NULL REFERENCES "catalogo_antecedentes" ("id_catalogo_antecedente") DEFERRABLE INITIALLY DEFERRED, "id_registro_antecedente" integer NOT NULL REFERENCES "registros_antecedentes_medicos" ("id_registro_antecedente") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "registros_antecedentes_medicos" ("id_registro_antecedente" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_registro" datetime NOT NULL, "observaciones_generales" text NULL, "id_paciente" integer NOT NULL REFERENCES "pacientes" ("id_paciente") DEFERRABLE INITIALLY DEFERRED, "id_usuario_registra" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "roles" ("id_rol" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(50) NOT NULL UNIQUE, "descripcion" varchar(150) NULL, "estado_rol" varchar(20) NOT NULL);
CREATE TABLE "sexos" ("id_sexo" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(20) NOT NULL UNIQUE);
CREATE TABLE "tipos_atencion" ("id_tipo_atencion" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(80) NOT NULL UNIQUE, "descripcion" varchar(150) NULL, "duracion_estimada_min" smallint unsigned NOT NULL CHECK ("duracion_estimada_min" >= 0), "estado_tipo_atencion" varchar(20) NOT NULL);
CREATE TABLE "tipos_movimiento_caja" ("id_tipo_movimiento" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(30) NOT NULL UNIQUE, "descripcion" varchar(100) NULL);
CREATE TABLE "tratamientos" ("id_tratamiento" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "codigo" varchar(30) NOT NULL UNIQUE, "nombre" varchar(100) NOT NULL UNIQUE, "descripcion" varchar(200) NULL, "valor_referencial" decimal NOT NULL, "duracion_estimada_min" smallint unsigned NULL CHECK ("duracion_estimada_min" >= 0), "estado_tratamiento" varchar(20) NOT NULL);
CREATE TABLE "usuario_rol" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "id_usuario" integer NOT NULL REFERENCES "usuarios" ("id_usuario") DEFERRABLE INITIALLY DEFERRED, "id_rol" integer NOT NULL REFERENCES "roles" ("id_rol") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "usuarios" ("last_login" datetime NULL, "id_usuario" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "username" varchar(50) NOT NULL UNIQUE, "password_hash" varchar(255) NOT NULL, "estado_acceso" varchar(20) NOT NULL, "ultimo_acceso" datetime NULL, "fecha_creacion" datetime NOT NULL, "fecha_actualizacion" datetime NOT NULL, "is_staff" bool NOT NULL, "is_superuser" bool NOT NULL, "id_persona" integer NOT NULL UNIQUE REFERENCES "personas" ("id_persona") DEFERRABLE INITIALLY DEFERRED);
CREATE INDEX "personas_id_sexo_9df7cea2" ON "personas" ("id_sexo");
CREATE INDEX "idx_personas_id_sexo" ON "personas" ("id_sexo");
