CREATE INDEX "odontologo_especialidad_id_especialidad_32339702" ON "odontologo_especialidad" ("id_especialidad");
CREATE INDEX "odontologo_especialidad_id_odontologo_4a378b80" ON "odontologo_especialidad" ("id_odontologo");
CREATE UNIQUE INDEX "horarios_odontologo_id_odontologo_dia_semana_hora_inicio_hora_fin_683b73da_uniq" ON "horarios_odontologo" ("id_odontologo", "dia_semana", "hora_inicio", "hora_fin");
CREATE INDEX "horarios_odontologo_id_odontologo_4fcde714" ON "horarios_odontologo" ("id_odontologo");
CREATE INDEX "idx_citas_paciente" ON "citas" ("id_paciente");
CREATE INDEX "idx_citas_odontologo" ON "citas" ("id_odontologo");
CREATE INDEX "idx_citas_box" ON "citas" ("id_box");
CREATE INDEX "idx_citas_inicio_fin" ON "citas" ("fecha_hora_inicio", "fecha_hora_fin");
