CREATE INDEX "citas_id_paciente_08e9677c" ON "citas" ("id_paciente");
CREATE INDEX "citas_id_usuario_registra_8cc8c2dc" ON "citas" ("id_usuario_registra");
CREATE INDEX "citas_id_estado_cita_817d0ee6" ON "citas" ("id_estado_cita");
CREATE INDEX "citas_id_tipo_atencion_683e7f68" ON "citas" ("id_tipo_atencion");
