CREATE INDEX "historial_citas_id_estado_anterior_5f0eb788" ON "historial_citas" ("id_estado_anterior");
CREATE INDEX "historial_citas_id_estado_nuevo_f11575b1" ON "historial_citas" ("id_estado_nuevo");
